"""
This module contains the Game class to manage the game flow.
"""

from board import Board, Piece

class Player:
    def __init__(self, color):
        self.color = color

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'black'

    def switch_player(self):
        if self.current_player == 'black':
            self.current_player = 'white'
        else:
            self.current_player = 'black'

    def play_move(self, from_pos, to_pos):
        if self.board.move(from_pos, to_pos):
            self.switch_player()
            return True
        return False

    def display_board(self):
        self.board.display()

if __name__ == "__main__":
    game = Game()
    game.display_board()
    while True:
        move = input(f"Player {game.current_player}, enter your move (e.g., A1-B2): ")
        from_pos = (8 - int(move[1]), ord(move[0]) - 97)
        to_pos = (8 - int(move[3]), ord(move[2]) - 97)
        if game.play_move(from_pos, to_pos):
